import{_ as e,o as l,c as i,a9 as t}from"./chunks/framework.STMWz9Nm.js";const f=JSON.parse('{"title":"Netty学习","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/12-Netty学习/12-Netty学习.md","filePath":"语言/java/12-Netty学习/12-Netty学习.md","lastUpdated":1776149370000}'),r={name:"语言/java/12-Netty学习/12-Netty学习.md"};function n(h,a,o,d,_,s){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="netty学习" tabindex="-1">Netty学习 <a class="header-anchor" href="#netty学习" aria-label="Permalink to “Netty学习”">​</a></h1><p>Netty 是 Java 里最重要的高性能网络编程框架之一。<br> 学习 Netty 的重点，不只是会搭个 server，而是理解事件驱动、线程模型、协议处理和性能设计。</p><h2 id="专题目录" tabindex="-1">专题目录 <a class="header-anchor" href="#专题目录" aria-label="Permalink to “专题目录”">​</a></h2><ul><li><a href="./01-架构与事件驱动.html">01-架构与事件驱动</a></li><li><a href="./02-ByteBuf与编解码.html">02-ByteBuf与编解码</a></li><li><a href="./03-Channel与Pipeline.html">03-Channel与Pipeline</a></li><li><a href="./04-粘包拆包与协议设计.html">04-粘包拆包与协议设计</a></li><li><a href="./05-线程模型与性能优化.html">05-线程模型与性能优化</a></li><li><a href="./06-实战思路与常见问题.html">06-实战思路与常见问题</a></li></ul><h2 id="_1-学习定位" tabindex="-1">1. 学习定位 <a class="header-anchor" href="#_1-学习定位" aria-label="Permalink to “1. 学习定位”">​</a></h2><p>这一组内容用于补充 Java 后端里的网络通信能力。<br> 目标是让你理解 Netty 为什么高效、它如何组织网络事件，以及如何设计更稳的协议处理链路。</p><h2 id="_2-学习重点" tabindex="-1">2. 学习重点 <a class="header-anchor" href="#_2-学习重点" aria-label="Permalink to “2. 学习重点”">​</a></h2><ul><li>理解事件驱动和 Reactor 思想</li><li>理解 ByteBuf、Channel、Pipeline 的协作方式</li><li>理解 TCP 粘包拆包问题</li><li>理解线程模型和性能优化手段</li><li>理解 Netty 在 RPC、网关、IM 等系统中的价值</li></ul><h2 id="_3-建议顺序" tabindex="-1">3. 建议顺序 <a class="header-anchor" href="#_3-建议顺序" aria-label="Permalink to “3. 建议顺序”">​</a></h2><ol><li>架构与事件驱动</li><li>ByteBuf 与编解码</li><li>Channel 与 Pipeline</li><li>粘包拆包与协议设计</li><li>线程模型与性能优化</li><li>实战思路与常见问题</li></ol><h2 id="_4-阶段产出" tabindex="-1">4. 阶段产出 <a class="header-anchor" href="#_4-阶段产出" aria-label="Permalink to “4. 阶段产出”">​</a></h2><ul><li>一份 Netty 核心组件关系图</li><li>一份协议设计与拆包处理笔记</li><li>一份性能优化与排障清单</li></ul><h2 id="_5-自测标准" tabindex="-1">5. 自测标准 <a class="header-anchor" href="#_5-自测标准" aria-label="Permalink to “5. 自测标准”">​</a></h2><ul><li>能解释 Netty 为什么适合高并发网络场景</li><li>能说清 Channel、EventLoop、Pipeline 的关系</li><li>能说明粘包拆包为什么必须在协议层处理</li></ul>',14)])])}const m=e(r,[["render",n]]);export{f as __pageData,m as default};
